"use client";
import Link from "next/link";
import { useAuth } from "../context/AuthContext";

export default function Navbar() {
  const { user, logout } = useAuth();

  return (
    <nav className="bg-gray-900 text-white px-6 py-4 flex justify-between items-center shadow-lg">
      <div className="flex items-center gap-4">
        <span className="font-bold text-2xl">Eventify</span>
        <input 
          type="text" 
          placeholder="Search events, artists, venues..." 
          className="px-3 py-1 rounded text-black"
        />
      </div>
      <div className="flex items-center gap-4">
        <Link href="/events" className="hover:underline">Events</Link>
        <Link href="/booking" className="hover:underline">Seat Selection</Link>
        <Link href="/checkout" className="hover:underline">Checkout</Link>
        <Link href="/dashboard" className="hover:underline">Organizer</Link>
        {user ? (
          <>
            <span>{user.name}</span>
            <button onClick={logout} className="btn bg-red-500 hover:bg-red-600">Logout</button>
          </>
        ) : (
          <Link href="/login" className="btn bg-blue-500 hover:bg-blue-600">Sign In</Link>
        )}
      </div>
    </nav>
  );
}
